import { useEffect, useState } from "react";

import CourseBuyCard from "../Components/CourseBuyCard";
import LiOnWhatYouLearn from "../Components/Lists/LiOnWhatYouLearn";

function CoursePage() {
  const [whatYouLearn, setSkills] = useState([]);
  
  
  useEffect(() => {
    const data = ["HTML", "CSS", "JavaScript", "React", "Node.js"];
    setSkills(data);
  }, []);



  return (
    <div>
      <svg style={{ display: "none" }}>
        <use href="#id">
          <symbol id="check-icon" viewBox="0 -960 960 960">
            <path d="m382-339.38 345.54-345.54q8.92-8.93 20.88-9.12t21.27 9.12 9.31 21.38q0 12.08-9.31 21.39l-362.38 363q-10.85 10.84-25.31 10.84t-25.31-10.84l-167-167q-8.92-8.93-8.8-21.2.11-12.26 9.42-21.57t21.38-9.31q12.08 0 21.39 9.31z"></path>
          </symbol>
        </use>
      </svg>





      <div className="black-container-on-course-page">
        <div style={{margin:"30px"}}>
          <h2 style={{fontSize:"30px", margin:"20px"}} >Name</h2>
          <p>Оценка:</p>
          <p>Автор:</p>
        </div>
      </div>
      <div  style={{display:"flex", justifyContent:"space-between", padding:"40px"}}>
        <div style={{width:"60%"}}>
          <div style={{width:"80%",border:"1px solid #aaa", marginTop:"8px"}}>
            <p style={{fontSize:"24px", marginBottom:"10px", padding:"15px"}}><b>Чему вы научитесь</b></p> 
            <ul className="what-you-learn-list">
            {whatYouLearn.map((item, index) => (
              <LiOnWhatYouLearn key={index} Text={item}/>
                ))}
            </ul>
          </div>
        </div>
        <div style={{marginRight:"3%"}}>
          <CourseBuyCard/>
        </div>
      </div>
    </div>
  );
}

export default CoursePage;
